    21→const me = os.me.use(authMiddleware).handler(({ context }) => {
    22→	return {
    23→		id: context.user.id,
    24→		email: context.user.email,
    25→		name: context.user.name,
    26→		image: context.user.image ?? null,
    27→		activeOrganizationId:
    28→			((context.session as Record<string, unknown>).activeOrganizationId as
    29→				| string
    30→				| null) ?? null,
    31→	};
    32→});
    33→
    34→const listMyOrganizations = os.listMyOrganizations
    35→	.use(authMiddleware)
    36→	.handler(async ({ context }) => {
    37→		const memberships = await db
    38→			.select({
    39→				id: organization.id,
    40→				name: organization.name,
    41→				slug: organization.slug,
    42→				logo: organization.logo,
    43→			})
    44→			.from(member)
    45→			.innerJoin(organization, eq(member.organizationId, organization.id))
    46→			.where(eq(member.userId, context.user.id));
    47→
    48→		return memberships.map((m) => ({
    49→			id: m.id,
    50→			name: m.name,
    51→			slug: m.slug,
    52→			logo: m.logo ?? null,
    53→		}));
    54→	});
