     1→import type {
     2→	ProjectContributor as ProjectContributorBase,
     3→	ProjectDetailData,
     4→	ProjectError as ProjectErrorBase,
     5→	ProjectFeatureUsage,
     6→	ProjectInvestment,
     7→	ProjectTrendDataPoint as ProjectTrendDataPointBase,
     8→} from "@rudel/api-routes";
     9→import {
    10→	buildDateFilter,
    11→	escapeString,
    12→	queryClickhouse,
    13→} from "../clickhouse.js";
    14→
    15→const PROJECT_KEY_EXPR = `if(git_remote != '', git_remote, if(package_name != '', package_name, project_path))`;
    16→const PROJECT_DISPLAY_EXPR = `if(git_remote != '', arrayElement(splitByChar('/', git_remote), -1), arrayElement(splitByChar('/', project_path), -1))`;
    17→
    18→function buildProjectDisplaySubquery(
    19→	org: string,
    20→	escapedProjectPath: string,
    21→): string {
    22→	return `(
    23→    SELECT
    24→      if(
    25→        count() > 0,
    26→        any(${PROJECT_DISPLAY_EXPR}),
    27→        if(position('${escapedProjectPath}', '/') > 0, arrayElement(splitByChar('/', '${escapedProjectPath}'), -1), '${escapedProjectPath}')
    28→      ) as project_display
    29→    FROM rudel.session_analytics
    30→    WHERE organization_id = '${org}'
    31→      AND (
    32→        project_path = '${escapedProjectPath}'
    33→        OR git_remote = '${escapedProjectPath}'
    34→        OR ${PROJECT_KEY_EXPR} = '${escapedProjectPath}'
    35→      )
    36→      AND (git_remote != '' OR package_name != '' OR project_path != '')
    37→  )`;
    38→}
    39→
    40→export interface KnowledgeSilo {
    41→	project_path: string;
    42→	project_name?: string;
    43→	repository_name?: string;
    44→	sole_user: string;
    45→	sessions: number;
    46→	risk_level: "high" | "medium" | "low";
    47→}
    48→
    49→export interface ProjectActivity {
    50→	date: string;
    51→	project_path: string;
    52→	sessions: number;
    53→	unique_users: number;
    54→}
    55→
    56→export interface ProjectSummary {
    57→	total_projects: number;
    58→	projects_with_silos: number;
    59→	avg_users_per_project: number;
    60→	most_active_project: string;
    61→	most_active_sessions: number;
    62→}
    63→
    64→export type ProjectDetails = ProjectDetailData;
    65→
    66→export interface ProjectContributor extends ProjectContributorBase {
    67→	username?: string;
    68→	first_session: string;
    69→	last_session: string;
    70→}
    71→
    72→export interface ProjectError extends ProjectErrorBase {
    73→	first_seen: string;
    74→}
    75→
    76→export interface ProjectTrendDataPoint extends ProjectTrendDataPointBase {
    77→	project_name?: string;
    78→}
    79→
    80→/**
    81→ * Extract project name from path (last segment)
    82→ */
    83→function extractProjectName(projectPath: string): string {
    84→	if (!projectPath) return "";
    85→	const segments = projectPath.replace(/\\/g, "/").split("/").filter(Boolean);
    86→	return segments[segments.length - 1] || projectPath;
    87→}
    88→
    89→/**
    90→ * Extract repository name from path
    91→ */
    92→function extractRepositoryName(projectPath: string): string {
    93→	return extractProjectName(projectPath);
    94→}
    95→
    96→/**
    97→ * Get AI investment by project - where is time being spent?
    98→ */
    99→export async function getProjectInvestment(
   100→	orgId: string,
   101→	params: {
   102→		days?: number;
   103→		limit?: number;
   104→		offset?: number;
   105→		project_path?: string;
   106→		project_paths?: string[];
   107→	} = {},
   108→): Promise<ProjectInvestment[]> {
   109→	const {
   110→		days = 30,
   111→		limit = 20,
   112→		offset = 0,
   113→		project_path,
   114→		project_paths,
   115→	} = params;
   116→	const org = escapeString(orgId);
   117→	const d = Number(days);
   118→	const lim = Number(limit);
   119→	const off = Number(offset);
   120→
   121→	let projectFilter = "";
   122→	if (project_path) {
   123→		projectFilter = `AND project_path = '${escapeString(project_path)}'`;
   124→	} else if (project_paths && project_paths.length > 0) {
   125→		const escaped = project_paths.map((p) => `'${escapeString(p)}'`).join(", ");
   126→		projectFilter = `AND project_path IN (${escaped})`;
   127→	}
   128→
   129→	const query = `
   130→    WITH current_period AS (
   131→      SELECT
   132→        ${PROJECT_DISPLAY_EXPR} as project_display,
   133→        any(git_remote) as _git_remote,
   134→        any(project_path) as _project_path,
   135→        COUNT(*) as sessions,
   136→        COUNT(DISTINCT user_id) as unique_users,
   137→        SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
   138→        SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
   139→        SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
   140→        round(SUM(actual_duration_min), 2) as total_duration_min,
   141→        round(AVG(actual_duration_min), 2) as avg_session_duration_min,
   142→        round(AVG(success_score), 2) as success_rate
   143→      FROM rudel.session_analytics
   144→      WHERE ${buildDateFilter(d)}
   145→        AND organization_id = '${org}'
   146→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   147→        ${projectFilter}
   148→      GROUP BY ${PROJECT_DISPLAY_EXPR}
   149→    ),
   150→    previous_period AS (
   151→      SELECT
   152→        ${PROJECT_DISPLAY_EXPR} as project_display,
   153→        round(AVG(success_score), 2) as prev_success_rate
   154→      FROM rudel.session_analytics
   155→      WHERE session_date >= now64(3) - INTERVAL ${d * 2} DAY
   156→        AND session_date < now64(3) - INTERVAL ${d} DAY
   157→        AND organization_id = '${org}'
   158→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   159→        ${projectFilter}
   160→      GROUP BY ${PROJECT_DISPLAY_EXPR}
   161→    )
   162→    SELECT
   163→      c.project_display as repository,
   164→      c._git_remote as git_remote,
   165→      c._project_path as project_path,
   166→      c.sessions,
   167→      c.unique_users,
   168→      c.total_tokens,
   169→      c.input_tokens_sum as input_tokens,
   170→      c.output_tokens_sum as output_tokens,
   171→      c.total_duration_min,
   172→      c.avg_session_duration_min,
   173→      c.success_rate,
   174→      round((c.output_tokens_sum / 1000000.0) * 15.0 + (c.input_tokens_sum / 1000000.0) * 3.0, 4) as cost,
   175→      round(c.success_rate - ifNull(p.prev_success_rate, c.success_rate), 2) as success_rate_trend
   176→    FROM current_period c
   177→    LEFT JOIN previous_period p ON c.project_display = p.project_display
   178→    ORDER BY c.total_duration_min DESC
   179→    LIMIT ${lim}
   180→    OFFSET ${off}
   181→  `;
   182→
   183→	const results = await queryClickhouse<
   184→		ProjectInvestment & { git_remote?: string }
   185→	>(query);
   186→
   187→	return results.map((project) => ({
   188→		...project,
   189→		repository: project.repository || null,
   190→		git_remote: project.git_remote || undefined,
   191→	}));
   192→}
   193→
   194→/**
   195→ * Get knowledge silos - projects with only one developer
   196→ */
   197→export async function getKnowledgeSilos(
   198→	orgId: string,
   199→	params: { days?: number; min_sessions?: number } = {},
   200→): Promise<KnowledgeSilo[]> {
   201→	const { days = 30, min_sessions = 5 } = params;
   202→	const org = escapeString(orgId);
   203→	const d = Number(days);
   204→	const minSess = Number(min_sessions);
   205→
   206→	const query = `
   207→    SELECT
   208→      project_path,
   209→      any(user_id) as sole_user,
   210→      COUNT(*) as sessions,
   211→      CASE
   212→        WHEN COUNT(*) >= 20 THEN 'high'
   213→        WHEN COUNT(*) >= 10 THEN 'medium'
   214→        ELSE 'low'
   215→      END as risk_level
   216→    FROM rudel.session_analytics
   217→    WHERE ${buildDateFilter(d)}
   218→      AND organization_id = '${org}'
   219→      AND project_path != ''
   220→    GROUP BY project_path
   221→    HAVING COUNT(DISTINCT user_id) = 1
   222→      AND COUNT(*) >= ${minSess}
   223→    ORDER BY sessions DESC
   224→  `;
   225→
   226→	const results = await queryClickhouse<KnowledgeSilo>(query);
   227→
   228→	return results.map((silo) => ({
   229→		...silo,
   230→		project_name: extractProjectName(silo.project_path),
   231→		repository_name: extractRepositoryName(silo.project_path),
   232→	}));
   233→}
   234→
   235→/**
   236→ * Get project activity trend over time
   237→ */
   238→export async function getProjectActivity(
   239→	orgId: string,
   240→	projectPath: string,
   241→	params: { days?: number; granularity?: "day" | "week" | "month" } = {},
   242→): Promise<ProjectActivity[]> {
   243→	const { days = 30, granularity = "day" } = params;
   244→	const org = escapeString(orgId);
   245→	const pp = escapeString(projectPath);
   246→	const d = Number(days);
   247→
   248→	let dateGrouping = "toDate(session_date)";
   249→	if (granularity === "week") {
   250→		dateGrouping = "toMonday(session_date)";
   251→	} else if (granularity === "month") {
   252→		dateGrouping = "toStartOfMonth(session_date)";
   253→	}
   254→
   255→	const query = `
   256→    WITH project_key AS (
   257→      SELECT if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) as pk, any(project_path) as project_path
   258→      FROM rudel.session_analytics
   259→      WHERE project_path = '${pp}'
   260→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   261→        AND organization_id = '${org}'
   262→      LIMIT 1
   263→    )
   264→    SELECT
   265→      toString(${dateGrouping}) as date,
   266→      pk.project_path,
   267→      COUNT(*) as sessions,
   268→      COUNT(DISTINCT s.user_id) as unique_users
   269→    FROM project_key pk
   270→    INNER JOIN rudel.session_analytics s ON if(s.git_remote != '', s.git_remote, if(s.package_name != '', s.package_name, s.project_path)) = pk.pk
   271→    WHERE s.${buildDateFilter(d)}
   272→      AND s.organization_id = '${org}'
   273→    GROUP BY ${dateGrouping}, pk.project_path
   274→    ORDER BY date ASC
   275→  `;
   276→
   277→	return queryClickhouse<ProjectActivity>(query);
   278→}
   279→
   280→/**
   281→ * Get project summary statistics
   282→ */
   283→export async function getProjectSummary(
   284→	orgId: string,
   285→	days = 30,
   286→): Promise<ProjectSummary> {
   287→	const org = escapeString(orgId);
   288→	const d = Number(days);
   289→
   290→	const query = `
   291→    WITH project_stats AS (
   292→      SELECT
   293→        project_path,
   294→        COUNT(*) as sessions,
   295→        COUNT(DISTINCT user_id) as users
   296→      FROM rudel.session_analytics
   297→      WHERE ${buildDateFilter(d)}
   298→        AND organization_id = '${org}'
   299→        AND project_path != ''
   300→      GROUP BY project_path
   301→    )
   302→    SELECT
   303→      COUNT(*) as total_projects,
   304→      countIf(users = 1 AND sessions >= 5) as projects_with_silos,
   305→      round(AVG(users), 2) as avg_users_per_project,
   306→      argMax(project_path, sessions) as most_active_project,
   307→      max(sessions) as most_active_sessions
   308→    FROM project_stats
   309→  `;
   310→
   311→	const result = await queryClickhouse<ProjectSummary>(query);
   312→	return (
   313→		result[0] || {
   314→			total_projects: 0,
   315→			projects_with_silos: 0,
   316→			avg_users_per_project: 0,
   317→			most_active_project: "",
   318→			most_active_sessions: 0,
   319→		}
   320→	);
   321→}
   322→
   323→/**
   324→ * Get detailed metrics for a specific project
   325→ */
   326→export async function getProjectDetails(
   327→	orgId: string,
   328→	projectPath: string,
   329→	days = 30,
   330→): Promise<ProjectDetails | null> {
   331→	const org = escapeString(orgId);
   332→	const pp = escapeString(projectPath);
   333→	const d = Number(days);
   334→	const projectDisplaySubquery = buildProjectDisplaySubquery(org, pp);
   335→
   336→	const query = `
   337→    SELECT
