    24→      if(
    25→        count() > 0,
    26→        any(${PROJECT_DISPLAY_EXPR}),
    27→        if(position('${escapedProjectPath}', '/') > 0, arrayElement(splitByChar('/', '${escapedProjectPath}'), -1), '${escapedProjectPath}')
    28→      ) as project_display
    29→    FROM rudel.session_analytics
    30→    WHERE organization_id = '${org}'
    31→      AND (
    32→        project_path = '${escapedProjectPath}'
    33→        OR git_remote = '${escapedProjectPath}'
    34→        OR ${PROJECT_KEY_EXPR} = '${escapedProjectPath}'
    35→      )
    36→      AND (git_remote != '' OR package_name != '' OR project_path != '')
    37→  )`;
