    96→/**
    97→ * Get AI investment by project - where is time being spent?
    98→ */
    99→export async function getProjectInvestment(
   100→	orgId: string,
   101→	params: {
   102→		days?: number;
   103→		limit?: number;
   104→		offset?: number;
   105→		project_path?: string;
   106→		project_paths?: string[];
   107→	} = {},
   108→): Promise<ProjectInvestment[]> {
   109→	const {
   110→		days = 30,
   111→		limit = 20,
   112→		offset = 0,
   113→		project_path,
   114→		project_paths,
   115→	} = params;
   116→	const org = escapeString(orgId);
   117→	const d = Number(days);
   118→	const lim = Number(limit);
   119→	const off = Number(offset);
   120→
   121→	let projectFilter = "";
   122→	if (project_path) {
   123→		projectFilter = `AND project_path = '${escapeString(project_path)}'`;
   124→	} else if (project_paths && project_paths.length > 0) {
   125→		const escaped = project_paths.map((p) => `'${escapeString(p)}'`).join(", ");
   126→		projectFilter = `AND project_path IN (${escaped})`;
   127→	}
   128→
   129→	const query = `
   130→    WITH current_period AS (
   131→      SELECT
   132→        ${PROJECT_DISPLAY_EXPR} as project_display,
   133→        any(git_remote) as _git_remote,
   134→        any(project_path) as _project_path,
   135→        COUNT(*) as sessions,
   136→        COUNT(DISTINCT user_id) as unique_users,
   137→        SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
   138→        SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
   139→        SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
   140→        round(SUM(actual_duration_min), 2) as total_duration_min,
   141→        round(AVG(actual_duration_min), 2) as avg_session_duration_min,
   142→        round(AVG(success_score), 2) as success_rate
   143→      FROM rudel.session_analytics
   144→      WHERE ${buildDateFilter(d)}
   145→        AND organization_id = '${org}'
   146→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   147→        ${projectFilter}
   148→      GROUP BY ${PROJECT_DISPLAY_EXPR}
   149→    ),
   150→    previous_period AS (
   151→      SELECT
   152→        ${PROJECT_DISPLAY_EXPR} as project_display,
   153→        round(AVG(success_score), 2) as prev_success_rate
   154→      FROM rudel.session_analytics
   155→      WHERE session_date >= now64(3) - INTERVAL ${d * 2} DAY
   156→        AND session_date < now64(3) - INTERVAL ${d} DAY
   157→        AND organization_id = '${org}'
   158→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   159→        ${projectFilter}
   160→      GROUP BY ${PROJECT_DISPLAY_EXPR}
   161→    )
   162→    SELECT
   163→      c.project_display as repository,
   164→      c._git_remote as git_remote,
   165→      c._project_path as project_path,
   166→      c.sessions,
   167→      c.unique_users,
   168→      c.total_tokens,
   169→      c.input_tokens_sum as input_tokens,
   170→      c.output_tokens_sum as output_tokens,
   171→      c.total_duration_min,
   172→      c.avg_session_duration_min,
   173→      c.success_rate,
   174→      round((c.output_tokens_sum / 1000000.0) * 15.0 + (c.input_tokens_sum / 1000000.0) * 3.0, 4) as cost,
   175→      round(c.success_rate - ifNull(p.prev_success_rate, c.success_rate), 2) as success_rate_trend
   176→    FROM current_period c
   177→    LEFT JOIN previous_period p ON c.project_display = p.project_display
   178→    ORDER BY c.total_duration_min DESC
   179→    LIMIT ${lim}
   180→    OFFSET ${off}
   181→  `;
   182→
   183→	const results = await queryClickhouse<
   184→		ProjectInvestment & { git_remote?: string }
   185→	>(query);
   186→
   187→	return results.map((project) => ({
   188→		...project,
   189→		repository: project.repository || null,
   190→		git_remote: project.git_remote || undefined,
   191→	}));
   192→}
