   542→/**
   543→ * Get error patterns specific to a project
   544→ */
   545→export async function getProjectErrors(
   546→	orgId: string,
   547→	projectPath: string,
   548→	days = 30,
   549→): Promise<ProjectError[]> {
   550→	const org = escapeString(orgId);
   551→	const pp = escapeString(projectPath);
   552→	const d = Number(days);
   553→	const projectDisplaySubquery = buildProjectDisplaySubquery(org, pp);
   554→
   555→	const query = `
   556→    WITH error_extracts AS (
   557→      SELECT
   558→        session_id,
   559→        user_id,
   560→        session_date,
   561→        CASE
   562→          WHEN content LIKE '%OperationFailed%' THEN 'OperationFailed'
   563→          WHEN content LIKE '%UnknownError%' THEN 'UnknownError'
   564→          WHEN content LIKE '%ORPCError%' THEN 'ORPCError'
   565→          WHEN content LIKE '%TimeoutError%' THEN 'TimeoutError'
   566→          WHEN content LIKE '%TypeError%' THEN 'TypeError'
   567→          WHEN content LIKE '%ReferenceError%' THEN 'ReferenceError'
   568→          WHEN content LIKE '%Error:%' OR content LIKE '%error:%' THEN 'GenericError'
   569→          ELSE NULL
   570→        END as error_pattern
   571→      FROM rudel.session_analytics
   572→      WHERE ${PROJECT_DISPLAY_EXPR} = ${projectDisplaySubquery}
   573→        AND ${buildDateFilter(d)}
   574→        AND organization_id = '${org}'
   575→        AND (git_remote != '' OR package_name != '' OR project_path != '')
   576→        AND (content LIKE '%Error:%' OR content LIKE '%error:%')
   577→    )
   578→    SELECT
   579→      error_pattern,
   580→      COUNT(*) as occurrences,
   581→      uniq(user_id) as affected_users,
   582→      toString(min(session_date)) as first_seen,
   583→      toString(max(session_date)) as last_seen
   584→    FROM error_extracts
   585→    WHERE error_pattern IS NOT NULL
   586→    GROUP BY error_pattern
   587→    ORDER BY occurrences DESC
   588→    LIMIT 20
   589→  `;
   590→
   591→	return queryClickhouse<ProjectError>(query);
   592→}
